@Service
public class TransferService {

    @Autowired
    private AccountRepository accountRepository;

    @Transactional  // Sab ya kuch nahi!
    public void transfer(Long fromId, Long toId, double amount) {
        Account from = accountRepository.findById(fromId)
            .orElseThrow(() -> new RuntimeException("Account nahi mila"));
        Account to = accountRepository.findById(toId)
            .orElseThrow(() -> new RuntimeException("Account nahi mila"));

        if (from.getBalance() < amount) {
            throw new RuntimeException("Paisa kam hai!");
            // Exception pe sab ROLLBACK ho jaayega
        }

        from.setBalance(from.getBalance() - amount);
        to.setBalance(to.getBalance() + amount);

        accountRepository.save(from);
        accountRepository.save(to);
        // Agar yahan koi error aaye, dono saves rollback!
    }
}

